{
  "name": "Insizwa Nobunsizwa - Cultural NGO",
  "description": "A cultural and social restoration platform for young Zulu men, founded by Phakela Umthakathi, focusing on dignity, discipline, and traditional heritage."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { About } from './components/About';
import { Programs } from './components/Programs';
import { GetInvolved } from './components/GetInvolved';
import { Footer } from './components/Footer';
import { WisdomSection } from './components/WisdomSection';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState('home');

  useEffect(() => {
    const handleScroll = () => {
      const sections = ['home', 'about', 'programs', 'wisdom', 'involved'];
      for (const section of sections) {
        const element = document.getElementById(section);
        if (element) {
          const rect = element.getBoundingClientRect();
          if (rect.top >= 0 && rect.top <= 300) {
            setActiveSection(section);
            break;
          }
        }
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div className="min-h-screen flex flex-col scroll-smooth">
      <Navbar activeSection={activeSection} />

      <main className="flex-grow">
        <section id="home">
          <Hero />
        </section>

        <section id="about" className="py-20 bg-white">
          <About />
        </section>

        <section id="programs" className="py-20 bg-[#f9f7f2]">
          <Programs />
        </section>

        <section id="wisdom" className="py-20 bg-[#1A1A1A] text-white">
          <WisdomSection />
        </section>

        <section id="involved" className="py-20 bg-white">
          <GetInvolved />
        </section>
      </main>

      <Footer />
    </div>
  );
};

export default App;

export interface Program {
  title: string;
  zuluTitle: string;
  description: string;
  icon: string;
}

export interface Value {
  title: string;
  zuluTitle: string;
  description: string;
}

export interface WisdomResponse {
  advice: string;
  zuluProverb: string;
  meaning: string;
}

import React, { useState } from 'react';

interface NavbarProps {
  activeSection: string;
}

export const Navbar: React.FC<NavbarProps> = ({ activeSection }) => {
  const [isOpen, setIsOpen] = useState(false);

  const navLinks = [
    { id: 'home', label: 'Ekhaya' },
    { id: 'about', label: 'Mayelana Nathi' },
    { id: 'programs', label: 'Izinhlelo' },
    { id: 'wisdom', label: 'Ukuhlakanipha' },
    { id: 'involved', label: 'Bamba Iqhaza' },
  ];

  return (
    <nav className="fixed w-full z-50 bg-[#4A2C2A]/90 backdrop-blur-md text-white shadow-xl">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-20">
          <div className="flex-shrink-0 flex items-center space-x-2">
            <div className="w-10 h-10 bg-[#D4AF37] rounded-full flex items-center justify-center text-[#4A2C2A] font-bold text-xl border-2 border-white">
              IN
            </div>
            <span className="font-bold text-lg tracking-wider uppercase">Insizwa Nobunsizwa</span>
          </div>

          <div className="hidden md:block">
            <div className="ml-10 flex items-baseline space-x-6">
              {navLinks.map((link) => (
                <a
                  key={link.id}
                  href={`#${link.id}`}
                  className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                    activeSection === link.id ? 'text-[#D4AF37] underline decoration-2 underline-offset-8' : 'hover:text-[#D4AF37]'
                  }`}
                >
                  {link.label}
                </a>
              ))}
              <a
                href="#involved"
                className="bg-[#D4AF37] text-[#4A2C2A] px-6 py-2 rounded-full font-bold hover:bg-white transition-all transform hover:scale-105"
              >
                Donate
              </a>
            </div>
          </div>

          <div className="md:hidden">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="inline-flex items-center justify-center p-2 rounded-md text-white hover:text-[#D4AF37] focus:outline-none"
            >
              <i className={`fa-solid ${isOpen ? 'fa-xmark' : 'fa-bars'} text-2xl`}></i>
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-[#4A2C2A] border-t border-[#D4AF37]/30 px-2 pt-2 pb-3 space-y-1 sm:px-3">
          {navLinks.map((link) => (
            <a
              key={link.id}
              href={`#${link.id}`}
              onClick={() => setIsOpen(false)}
              className="block px-3 py-2 rounded-md text-base font-medium hover:bg-[#D4AF37]/10"
            >
              {link.label}
            </a>
          ))}
          <a
            href="#involved"
            onClick={() => setIsOpen(false)}
            className="block w-full text-center bg-[#D4AF37] text-[#4A2C2A] px-3 py-3 rounded-md font-bold"
          >
            Support the Vision
          </a>
        </div>
      )}
    </nav>
  );
};

import React, { useState } from 'react';
import { GoogleGenAI, Type } from '@google/genai';

export const WisdomSection: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [wisdom, setWisdom] = useState<{ advice: string; zuluProverb: string; meaning: string } | null>(null);
  const [category, setCategory] = useState('Conflict');

  const generateWisdom = async () => {
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Act as a wise Zulu elder and mentor from Insizwa Nobunsizwa. 
        Provide a traditional Zulu proverb related to "${category}", its English meaning, and brief cultural advice for a young man (insizwa).`,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              advice: { type: Type.STRING },
              zuluProverb: { type: Type.STRING },
              meaning: { type: Type.STRING }
            },
            required: ['advice', 'zuluProverb', 'meaning']
          }
        }
      });

      const data = JSON.parse(response.text);
      setWisdom(data);
    } catch (error) {
      console.error('Error generating wisdom:', error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
      <div className="grid lg:grid-cols-2 gap-16 items-center">
        <div>
          <h2 className="text-[#D4AF37] font-bold text-sm uppercase tracking-widest mb-4">Ukuhlakanipha / Wisdom</h2>
          <h3 className="text-4xl md:text-5xl font-black mb-8">Ask the Wise Elder</h3>
          <p className="text-gray-400 text-lg mb-10">
            In our tradition, the youth seek counsel from the elders to navigate the complexities of life. 
            Choose a challenge you are facing, and let the ancestors guide you.
          </p>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 mb-8">
            {['Conflict', 'Leadership', 'Discipline', 'Respect', 'Purpose', 'Courage'].map((cat) => (
              <button
                key={cat}
                onClick={() => setCategory(cat)}
                className={`py-3 px-4 rounded-lg font-bold transition-all border ${
                  category === cat ? 'bg-[#D4AF37] text-[#4A2C2A] border-[#D4AF37]' : 'bg-transparent text-gray-400 border-gray-700 hover:border-[#D4AF37]'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>

          <button
            onClick={generateWisdom}
            disabled={loading}
            className="w-full py-5 bg-white text-[#4A2C2A] font-bold rounded-full text-xl hover:bg-[#D4AF37] transition-all disabled:opacity-50 flex items-center justify-center space-x-4 shadow-[0_0_30px_rgba(255,255,255,0.1)]"
          >
            {loading ? (
              <i className="fa-solid fa-spinner fa-spin"></i>
            ) : (
              <>
                <i className="fa-solid fa-scroll"></i>
                <span>Receive Counsel</span>
              </>
            )}
          </button>
        </div>

        <div className="relative min-h-[400px] flex items-center justify-center">
           {wisdom ? (
             <div className="w-full bg-gradient-to-br from-[#2a2a2a] to-[#1a1a1a] p-10 rounded-3xl border border-[#D4AF37]/30 animate-in fade-in slide-in-from-bottom-4 duration-700">
                <i className="fa-solid fa-quote-left text-[#D4AF37] text-5xl mb-6 opacity-40"></i>
                <h4 className="text-2xl md:text-3xl font-black text-[#D4AF37] mb-4 italic">
                  "{wisdom.zuluProverb}"
                </h4>
                <p className="text-gray-400 text-sm uppercase tracking-widest font-bold mb-6">
                  Literal Meaning: {wisdom.meaning}
                </p>
                <div className="h-px w-20 bg-[#D4AF37] mb-6"></div>
                <p className="text-gray-200 text-lg leading-relaxed italic">
                  {wisdom.advice}
                </p>
             </div>
           ) : (
             <div className="text-center text-gray-600 border-2 border-dashed border-gray-800 p-20 rounded-3xl w-full">
               <i className="fa-solid fa-wand-magic-sparkles text-6xl mb-6 opacity-20"></i>
               <p className="text-xl">Select a category and receive the elder's wisdom</p>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

