                {/* Main Hero Image */}
                <div 
                  className="h-60 md:h-80 overflow-hidden relative cursor-zoom-in"
                  onClick={() => setActiveImage(selectedEventImages[event.id] || event.image)}
                >
                  <img 
                    src={selectedEventImages[event.id] || event.image} 
                    className="w-full h-full object-cover grayscale transition-all duration-1000 group-hover:grayscale-0 group-hover:scale-105" 
                    alt={event.title} 
                  />
                  <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                    <div className="w-12 h-12 bg-white/20 backdrop-blur-xl rounded-full flex items-center justify-center text-white border border-white/20">
                      <i className="fa-solid fa-expand"></i>
                    </div>
                  </div>
                  <div className="absolute top-6 right-6 bg-[#4A2C2A]/80 backdrop-blur-md px-4 py-1.5 rounded-full text-[9px] font-black text-[#D4AF37] uppercase tracking-widest shadow-xl">
                    {event.category}
