                </div>

                <div className="p-10 md:p-14">
                  <div className="flex items-center gap-3 mb-4">
                    <span className="w-8 h-px bg-[#D4AF37]"></span>
                    <p className="text-[#D4AF37] font-black text-[10px] uppercase tracking-widest">{event.date}</p>
                  </div>
                  <h4 className="text-2xl md:text-4xl font-black text-[#4A2C2A] mb-4 tracking-tighter leading-[0.9]">{event.title}</h4>
                  <p className="text-gray-500 text-sm md:text-lg mb-8 leading-relaxed font-light">{event.description}</p>

                  {/* Enhanced Thumbnail Gallery */}
                  {event.images && event.images.length > 0 && (
                    <div className="mb-10">
                      <h5 className="text-[9px] font-black uppercase text-[#4A2C2A]/40 tracking-[0.2em] mb-4 flex items-center gap-3">
                        Event Gallery
                        <div className="flex-grow h-px bg-gray-100"></div>
                      </h5>
                      <div className="flex gap-3 overflow-x-auto pb-4 scrollbar-hide">
                        {event.images.map((img, i) => {
                          const isCurrent = (selectedEventImages[event.id] || event.image) === img;
                          return (
                            <button 
                              key={i} 
                              onClick={() => handleThumbnailClick(event.id, img)}
                              className={`flex-shrink-0 w-16 h-16 md:w-20 md:h-20 rounded-2xl overflow-hidden border-2 transition-all duration-500 relative ${
                                isCurrent 
                                  ? 'border-[#D4AF37] scale-110 shadow-2xl z-10' 
                                  : 'border-transparent grayscale hover:grayscale-0 opacity-60 hover:opacity-100'
                              }`}
                            >
                              <img src={img} className="w-full h-full object-cover" alt={`Gallery ${i}`} />
                              {isCurrent && (
                                <div className="absolute inset-0 bg-[#D4AF37]/10 pointer-events-none"></div>
                              )}
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  )}

                  <button className="text-[#4A2C2A] font-black uppercase text-[10px] tracking-widest flex items-center gap-3 group/btn hover:text-[#D4AF37] transition-colors">
                    Access Report 
                    <i className="fa-solid fa-arrow-right transition-transform group-hover/btn:translate-x-2"></i>
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Lightbox / Video Modal */}
      {(activeVideoId || activeImage) && (
        <div 
          className="fixed inset-0 z-[100] bg-[#4A2C2A]/98 backdrop-blur-3xl flex items-center justify-center p-6 md:p-12"
          onClick={() => { setActiveVideoId(null); setActiveImage(null); }}
        >
          <button 
            className="absolute top-8 right-8 text-white/50 hover:text-[#D4AF37] text-4xl transition-all hover:rotate-90"
            onClick={() => { setActiveVideoId(null); setActiveImage(null); }}
          >
            <i className="fa-solid fa-xmark"></i>
          </button>

          <div 
            className="w-full max-w-6xl relative animate-in zoom-in duration-500"
            onClick={(e) => e.stopPropagation()}
          >
            {activeVideoId && activeVideo ? (
              <div className="aspect-video rounded-[2rem] md:rounded-[4rem] overflow-hidden border-8 border-white/5 shadow-[0_0_100px_rgba(0,0,0,0.5)]">
                <iframe 
                  src={`${activeVideo.videoUrl}?autoplay=1`} 
                  className="w-full h-full" 
                  frameBorder="0" 
                  allow="autoplay; encrypted-media" 
                  allowFullScreen
                ></iframe>
              </div>
            ) : activeImage ? (
              <div className="relative group">
                <img 
                  src={activeImage} 
                  className="w-full max-h-[85vh] object-contain rounded-[2rem] md:rounded-[4rem] border-8 border-white/5 shadow-[0_0_100px_rgba(0,0,0,0.5)]" 
                  alt="Lightbox" 
                />
                <div className="absolute -bottom-16 left-0 right-0 text-center">
                  <p className="text-[#D4AF37] font-black uppercase tracking-[0.4em] text-[10px]">Archived Master Record</p>
                </div>
              </div>
            ) : null}
          </div>
        </div>
      )}
    </div>
  );
};

